// Created: 2026-06-20

/**
 * Network Egress Guard - PreToolUse (Bash)
 *
 * Closes the one present-tense gap in ork's own (policy) lane: there was no
 * guard on the agent's OUTBOUND network commands. Composed into the synchronous
 * blocking lane (sync-bash-dispatcher) right after dangerous-command-blocker.
 *
 * Scope split (mirrors dangerous-command-blocker's DENY/ASK/ALLOW tiers):
 *
 *   DENY  — remote code execution via fetched content. Never legitimate for an
 *           agent: `bash <(curl …)`, `eval $(curl …)`, `nc -e` reverse shell.
 *           NOTE: `curl … | sh` / `… | base64 -d | sh` are ALREADY blocked by
 *           dangerous-command-blocker's PIPE_TO_SHELL_RE (runs first), so we do
 *           NOT duplicate the simple pipe-to-shell case here.
 *
 *   ASK   — sometimes-legitimate egress that is also the classic exfil/install
 *           vector: staged download-then-run (`curl -o x.sh … && sh x.sh`),
 *           data UPLOAD (POST/PUT/-d/-F/-T) to a non-allowlisted host, and
 *           nc/scp/rsync to a non-allowlisted host.
 *
 *   ALLOW — everything else (plain GET fetches to fetch info, allowlisted hosts).
 *
 * HONEST SCOPE: this is prevention, not containment. A regex/string guard is
 * bypassable (interpreter indirection, $IFS, char-by-char). It narrows the gap;
 * only a real boundary (CC `/sandbox` network-allowlist, or a container) closes
 * it. Pairs with the doctor sandbox-nudge (#2534). See milestone #160.
 *
 * Issue: #2533. CC 2.1.7 compliant (JSON with continue field via output builders).
 */

import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputDeny, outputAsk } from '../../lib/common.js';
import { normalizeSingle } from '../../lib/normalize-command.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'network-egress-guard';

// =============================================================================
// Allowlist — hosts the agent routinely + safely talks to. User-extensible via
// ORCHESTKIT_EGRESS_ALLOWLIST (comma-separated). Suffix-matched, so `github.com`
// also covers `api.github.com`, `raw.githubusercontent.com`, etc.
// =============================================================================

const DEFAULT_ALLOWLIST = [
  'github.com',
  'githubusercontent.com',
  'codeload.github.com',
  'registry.npmjs.org',
  'npmjs.com',
  'npmjs.org',
  'pypi.org',
  'files.pythonhosted.org',
  'crates.io',
  'api.anthropic.com',
  'localhost',
  '127.0.0.1',
  '0.0.0.0',
  '::1',
];

function allowlist(): string[] {
  const extra = (process.env.ORCHESTKIT_EGRESS_ALLOWLIST || '')
    .split(',')
    .map((h) => h.trim().toLowerCase())
    .filter(Boolean);
  return [...DEFAULT_ALLOWLIST, ...extra];
}

/** True when `host` is the allowlist entry or a subdomain of it. */
function isAllowlisted(host: string): boolean {
  const h = host.toLowerCase().replace(/:\d+$/, ''); // strip :port
  return allowlist().some((a) => h === a || h.endsWith(`.${a}`));
}

/** Extract hostnames from `http(s)://host[:port]/…` occurrences. */
function extractUrlHosts(cmd: string): string[] {
  const hosts: string[] = [];
  for (const m of cmd.matchAll(/https?:\/\/([^/\s"'`)]+)/gi)) {
    // strip credentials in `user:pass@host`
    hosts.push(m[1].replace(/^[^@]*@/, ''));
  }
  return hosts;
}

// =============================================================================
// DENY tier — remote code execution via fetched content
// =============================================================================

const DENY_REGEX: { re: RegExp; label: string }[] = [
  // interpreter reading a process-substitution network fetch: bash <(curl …)
  {
    re: /\b(?:ba|z|k|da)?sh\s+<\(\s*(?:curl|wget|fetch)\b/i,
    label: 'shell <(curl …) — executes fetched remote content',
  },
  {
    re: /\b(?:source|\.)\s+<\(\s*(?:curl|wget|fetch)\b/i,
    label: 'source <(curl …) — sources fetched remote content',
  },
  {
    re: /\b(?:python[0-9.]*|node|ruby|perl|php)\s+<\(\s*(?:curl|wget|fetch)\b/i,
    label: 'interpreter <(curl …) — runs fetched remote content',
  },
  // eval of a command substitution that fetches: eval $(curl …) / eval `curl …`
  {
    re: /\beval\b[^\n]{0,60}?(?:\$\(|`)\s*(?:curl|wget|fetch)\b/i,
    label: 'eval $(curl …) — evaluates fetched remote content',
  },
  // netcat reverse shell: nc -e /bin/sh host port
  {
    re: /\b(?:nc|ncat|netcat)\b[^\n]*\s-e\b/i,
    label: 'nc -e — netcat command-exec (reverse shell)',
  },
];

// =============================================================================
// ASK tier — sometimes-legit egress that is also the classic exfil vector
// =============================================================================

// Staged download-then-run: a fetch that writes a file, then an interpreter,
// joined by && / ; / newline. Catches `curl -o i.sh URL && bash i.sh`.
const STAGED_RUN_RE =
  /\b(?:curl|wget)\b[^\n]*?(?:\s-o\b|\s-O\b|\s--output\b|>)[^\n]*?(?:&&|;|\n)[^\n]*?\b(?:ba|z|k|da)?sh\b|\b(?:curl|wget)\b[^\n]*?(?:\s-o\b|\s-O\b|\s--output\b|>)[^\n]*?(?:&&|;|\n)[^\n]*?\b(?:source|python[0-9.]*|node|ruby|perl)\b/i;

// curl/wget that UPLOADS data (vs a plain GET). Presence of any of these = a
// body/method that sends data out.
const UPLOAD_RE =
  /(?:\s-d\b|\s--data(?:-binary|-raw|-urlencode)?\b|\s-F\b|\s--form\b|\s-T\b|\s--upload-file\b|-X\s+(?:POST|PUT|PATCH)\b|--request\s+(?:POST|PUT|PATCH)\b)/i;

const FETCH_RE = /\b(?:curl|wget)\b/i;
const NC_RE = /\b(?:nc|ncat|netcat)\b/i;
const SCP_RSYNC_REMOTE_RE = /\b(?:scp|rsync)\b[^\n]*?\b[\w.-]+@[\w.-]+:|(?:\brsync\b[^\n]*?\b[\w.-]+::)/i;

/** First non-flag token after an nc/scp invocation that looks like a host. */
function firstRemoteHost(cmd: string): string | null {
  // nc/ncat/netcat host port  (skip leading flags)
  const nc = cmd.match(/\b(?:nc|ncat|netcat)\s+((?:-\S+\s+)*)([\w.-]+)/i);
  if (nc?.[2] && !/^-/.test(nc[2])) return nc[2];
  // user@host: (scp/rsync)
  const at = cmd.match(/\b[\w.-]+@([\w.-]+):/);
  if (at) return at[1];
  return null;
}

// =============================================================================
// Main handler
// =============================================================================

export function networkEgressGuard(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const raw = input.tool_input?.command || '';
  if (!raw) return outputSilentSuccess();

  const command = normalizeSingle(raw);

  // --- DENY tier ---
  for (const { re, label } of DENY_REGEX) {
    if (re.test(command)) {
      ctx.log(HOOK_NAME, `BLOCKED: ${label}`);
      ctx.logPermission('deny', label, input);
      return outputDeny(
        `Blocked remote-code-execution pattern: ${label}\n\n` +
          'Fetching content from the network and executing it in one step is a ' +
          'common exfiltration / supply-chain vector and has been blocked. If this ' +
          'is intentional, download to a file, inspect it, then run it as a ' +
          'separate reviewed step.',
      );
    }
  }

  // --- ASK tier: staged download-then-run ---
  if (STAGED_RUN_RE.test(command)) {
    const reason = 'Downloads a script from the network and then executes it. Proceed?';
    ctx.log(HOOK_NAME, `ASK: staged download-then-run`);
    ctx.logPermission('ask', reason, input);
    return outputAsk(reason);
  }

  // --- ASK tier: data upload to a non-allowlisted host ---
  if (FETCH_RE.test(command) && UPLOAD_RE.test(command)) {
    const offHost = extractUrlHosts(command).find((h) => !isAllowlisted(h));
    if (offHost) {
      const reason = `Uploads data to a non-allowlisted host (${offHost}). Possible exfiltration. Proceed?`;
      ctx.log(HOOK_NAME, `ASK: data upload to ${offHost}`);
      ctx.logPermission('ask', reason, input);
      return outputAsk(reason);
    }
  }

  // --- ASK tier: nc / scp / rsync to a non-allowlisted host ---
  if (NC_RE.test(command) || SCP_RSYNC_REMOTE_RE.test(command)) {
    const host = firstRemoteHost(command);
    if (host && !isAllowlisted(host)) {
      const reason = `Opens a raw connection / transfers files to a non-allowlisted host (${host}). Proceed?`;
      ctx.log(HOOK_NAME, `ASK: raw/transfer to ${host}`);
      ctx.logPermission('ask', reason, input);
      return outputAsk(reason);
    }
  }

  return outputSilentSuccess();
}
